#include <bits/stdc++.h>
using namespace std;

int n, cnt[1005];

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        getchar();
        char c;
        c = getchar();
        if (c == 'p') {
            cnt[i + 1]++;
        }
        else {
            cnt[i - 1]++;
        }
    }
    int cnt0 = 0, cnt1 = 0, cnt2 = 0;
    for (int i = 1; i <= n; i++) {
        // cout << cnt[i] << ' ';
        switch (cnt[i]) {
            case 0:
                cnt0++;
                break;
            case 1:
                cnt1++;
                break;
            case 2:
                cnt2++;
                break;
        }
    }
    printf("%d %d %d\n", cnt0, cnt1, cnt2);
    return 0;
}
